class AdvancedDataFilteringService:
    def __init__(self, connection_string: str, database_name: str):
        self.query_service = SecureMongoDBQueryService(connection_string, database_name)
        self.query_service.disable_server_side_js()
    
    def filter_documents(self, collection_name: str, 
                        user_filters: str) -> List[Dict[str, Any]]:
        """
        Accept user-provided filters as JSON and execute safely
        """
        try:
            filters = json.loads(user_filters)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON format: {e}")
        
        safe_query = self.query_service.build_safe_query(filters)
        return self.query_service.execute_query(collection_name, safe_query)
    
    def advanced_search(self, collection_name: str,
                       search_criteria: Dict[str, Any],
                       sort_by: Optional[str] = None,
                       limit: int = 100) -> List[Dict[str, Any]]:
        """
        Perform advanced search with sorting
        """
        sanitized_query = self.query_service.sanitize_query(search_criteria)
        collection = self.query_service.db[collection_name]
        
        cursor = collection.find(sanitized_query)
        
        if sort_by and self.query_service.validate_field_name(sort_by):
            cursor = cursor.sort(sort_by, pymongo.ASCENDING)
        
        return list(cursor.limit(limit))
    
    def aggregate_data(self, collection_name: str,
                      pipeline_json: str) -> List[Dict[str, Any]]:
        """
        Execute aggregation pipeline from JSON input
        """
        try:
            pipeline = json.loads(pipeline_json)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON format: {e}")
        
        if not isinstance(pipeline, list):
            raise ValueError("Pipeline must be a list of stages")
        
        return self.query_service.execute_aggregation(collection_name, pipeline)
    
    def text_search(self, collection_name: str, 
                   search_text: str) -> List[Dict[str, Any]]:
        """
        Perform text search using MongoDB text index
        """
        query = {'$text': {'$search': search_text}}
        collection = self.query_service.db[collection_name]
        return list(collection.find(query))
    
    def range_query(self, collection_name: str, field: str,
                   min_value: Any, max_value: Any) -> List[Dict[str, Any]]:
        """
        Execute range queries safely
        """
        if not self.query_service.validate_field_name(field):
            raise ValueError(f"Invalid field name: {field}")
        
        query = {
            field: {
                '$gte': min_value,
                '$lte': max_value
            }
        }
        
        return self.query_service.execute_query(collection_name, query)
    
    def get_security_status(self) -> Dict[str, Any]:
        """
        Get security status of the MongoDB connection
        """
        js_enabled = self.query_service.check_js_status()
        return {
            'javascript_enabled': js_enabled,
            'secure_mode': not js_enabled if js_enabled is not None else 'unknown',
            'allowed_operators': list(self.query_service.allowed_operators)
        }


